import React, { useState, useEffect } from 'react';
import api from '../services/api';
import { useAuth } from '../context/AuthContext';

const Casino = () => {
  const [games, setGames] = useState([]);
  const [selectedGame, setSelectedGame] = useState(null);
  const [betAmount, setBetAmount] = useState(10);
  const [selection, setSelection] = useState('');
  const [result, setResult] = useState(null);
  const [playing, setPlaying] = useState(false);
  const { fetchBalance } = useAuth();

  useEffect(() => {
    loadGames();
  }, []);

  const loadGames = async () => {
    try {
      const res = await api.get('/api/casino/games');
      setGames(res.data);
    } catch (err) {
      console.error('Erro ao carregar jogos');
    }
  };

  const playGame = async () => {
    if (!selectedGame || betAmount <= 0) return;
    setPlaying(true);
    setResult(null);
    try {
      const res = await api.post('/api/casino/play', {
        gameId: selectedGame.id,
        betAmount: parseFloat(betAmount),
        selection: selection || undefined,
      });
      setTimeout(() => {
        setResult(res.data);
        fetchBalance();
        setPlaying(false);
      }, 1500);
    } catch (err) {
      setResult({ message: err.response?.data?.message || 'Erro ao jogar' });
      setPlaying(false);
    }
  };

  const gameIcons = {
    slots: '🎰', roulette: '🎡', crash: '📈',
    mines: '💣', dice: '🎲', aviator: '✈️',
  };

  const gameColors = {
    slots: '#DC0000', roulette: '#228B22', crash: '#FF6600',
    mines: '#8B0000', dice: '#4169E1', aviator: '#9400D3',
  };

  const renderGameControls = () => {
    if (!selectedGame) return null;
    switch (selectedGame.id) {
      case 'roulette':
        return (
          <div style={styles.controls}>
            <p style={styles.controlLabel}>Escolha sua aposta:</p>
            <div style={styles.controlGrid}>
              {['red', 'black', 'even', 'odd'].map(opt => (
                <button key={opt} onClick={() => setSelection(opt)}
                  style={{ ...styles.controlBtn, background: selection === opt ? '#FFD700' : '#2a2a2a', color: selection === opt ? '#000' : '#fff' }}>
                  {opt === 'red' ? '🔴 Vermelho' : opt === 'black' ? '⚫ Preto' : opt === 'even' ? 'Par' : 'Ímpar'}
                </button>
              ))}
            </div>
          </div>
        );
      case 'dice':
        return (
          <div style={styles.controls}>
            <p style={styles.controlLabel}>Escolha:</p>
            <div style={styles.controlGrid}>
              <button onClick={() => setSelection('above3')}
                style={{ ...styles.controlBtn, background: selection === 'above3' ? '#FFD700' : '#2a2a2a', color: selection === 'above3' ? '#000' : '#fff' }}>
                ⬆️ Acima de 3
              </button>
              <button onClick={() => setSelection('below4')}
                style={{ ...styles.controlBtn, background: selection === 'below4' ? '#FFD700' : '#2a2a2a', color: selection === 'below4' ? '#000' : '#fff' }}>
                ⬇️ Abaixo de 4
              </button>
            </div>
          </div>
        );
      case 'crash':
      case 'aviator':
        return (
          <div style={styles.controls}>
            <p style={styles.controlLabel}>Multiplicador para sacar (ex: 2.0):</p>
            <input className="input-field" type="number" step="0.1" min="1.1" placeholder="2.0"
              value={selection} onChange={(e) => setSelection(e.target.value)} />
          </div>
        );
      case 'mines':
        return (
          <div style={styles.controls}>
            <p style={styles.controlLabel}>Escolha uma célula (0-24):</p>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: '6px', maxWidth: '250px' }}>
              {Array.from({ length: 25 }, (_, i) => (
                <button key={i} onClick={() => setSelection(String(i))}
                  style={{
                    width: '44px', height: '44px', borderRadius: '8px', border: 'none', cursor: 'pointer',
                    background: selection === String(i) ? '#FFD700' : '#2a2a2a',
                    color: selection === String(i) ? '#000' : '#fff',
                    fontWeight: 600, fontSize: '13px',
                  }}>
                  {i}
                </button>
              ))}
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  const styles = {
    container: { maxWidth: '1200px', margin: '0 auto', padding: '20px' },
    title: {
      fontFamily: "'Orbitron', sans-serif", fontSize: '32px', fontWeight: 700,
      marginBottom: '8px', textAlign: 'center',
    },
    subtitle: { textAlign: 'center', color: '#b0b0b0', marginBottom: '32px', fontSize: '15px' },
    grid: {
      display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(170px, 1fr))',
      gap: '16px', marginBottom: '32px',
    },
    gameCard: (game, isSelected) => ({
      background: isSelected ? `linear-gradient(135deg, ${gameColors[game.id]}40, #1a1a1a)` : '#1a1a1a',
      border: isSelected ? `2px solid ${gameColors[game.id]}` : '1px solid #2a2a2a',
      borderRadius: '16px', padding: '24px', textAlign: 'center', cursor: 'pointer',
      transition: 'all 0.3s ease', transform: isSelected ? 'scale(1.05)' : 'scale(1)',
    }),
    gameIcon: { fontSize: '48px', marginBottom: '12px' },
    gameName: { fontFamily: "'Orbitron', sans-serif", fontSize: '16px', fontWeight: 600, color: '#FFD700', marginBottom: '6px' },
    gameDesc: { fontSize: '12px', color: '#b0b0b0' },
    playArea: {
      background: '#1a1a1a', border: '1px solid #2a2a2a', borderRadius: '16px',
      padding: '32px', marginTop: '24px',
    },
    playTitle: { fontFamily: "'Orbitron', sans-serif", fontSize: '22px', fontWeight: 600, marginBottom: '20px', color: '#FFD700' },
    betRow: { display: 'flex', gap: '12px', alignItems: 'center', marginBottom: '20px', flexWrap: 'wrap' },
    betLabel: { color: '#b0b0b0', fontSize: '14px', fontWeight: 500 },
    quickBets: { display: 'flex', gap: '8px', flexWrap: 'wrap' },
    quickBet: (active) => ({
      padding: '8px 16px', borderRadius: '8px', border: 'none', cursor: 'pointer',
      background: active ? '#FFD700' : '#2a2a2a', color: active ? '#000' : '#fff',
      fontWeight: 600, fontSize: '13px',
    }),
    controls: { marginBottom: '20px' },
    controlLabel: { color: '#b0b0b0', fontSize: '14px', marginBottom: '10px' },
    controlGrid: { display: 'flex', gap: '8px', flexWrap: 'wrap' },
    controlBtn: {
      padding: '10px 20px', borderRadius: '8px', border: 'none', cursor: 'pointer',
      fontWeight: 600, fontSize: '13px', transition: 'all 0.3s ease',
    },
    resultBox: (won) => ({
      marginTop: '20px', padding: '20px', borderRadius: '12px',
      background: won ? 'rgba(0,200,83,0.1)' : 'rgba(255,23,68,0.1)',
      border: `1px solid ${won ? 'rgba(0,200,83,0.3)' : 'rgba(255,23,68,0.3)'}`,
      textAlign: 'center', animation: 'slideUp 0.5s ease',
    }),
    resultMsg: (won) => ({
      fontSize: '18px', fontWeight: 700, color: won ? '#00c853' : '#ff1744',
      marginBottom: '8px',
    }),
    resultDetails: { color: '#b0b0b0', fontSize: '14px' },
    spinner: {
      display: 'inline-block', width: '40px', height: '40px',
      border: '4px solid #2a2a2a', borderTop: '4px solid #FFD700',
      borderRadius: '50%', animation: 'spin 1s linear infinite',
    },
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>🎰 <span className="gold-text">Cassino</span></h1>
      <p style={styles.subtitle}>Escolha seu jogo favorito e boa sorte!</p>

      <div style={styles.grid}>
        {games.map(game => (
          <div key={game.id} style={styles.gameCard(game, selectedGame?.id === game.id)}
            onClick={() => { setSelectedGame(game); setResult(null); setSelection(''); }}>
            <div style={styles.gameIcon}>{gameIcons[game.id]}</div>
            <div style={styles.gameName}>{game.name}</div>
            <div style={styles.gameDesc}>{game.description}</div>
          </div>
        ))}
      </div>

      {selectedGame && (
        <div style={styles.playArea}>
          <h3 style={styles.playTitle}>{gameIcons[selectedGame.id]} {selectedGame.name}</h3>

          <div style={styles.betRow}>
            <span style={styles.betLabel}>Valor da aposta: R$</span>
            <input className="input-field" type="number" min="1" value={betAmount}
              onChange={(e) => setBetAmount(e.target.value)}
              style={{ width: '120px' }} />
            <div style={styles.quickBets}>
              {[5, 10, 25, 50, 100].map(v => (
                <button key={v} style={styles.quickBet(betAmount === v)}
                  onClick={() => setBetAmount(v)}>R${v}</button>
              ))}
            </div>
          </div>

          {renderGameControls()}

          <button className="btn-gold" onClick={playGame} disabled={playing}
            style={{ padding: '14px 40px', fontSize: '16px' }}>
            {playing ? 'JOGANDO...' : '🎯 JOGAR AGORA'}
          </button>

          {playing && (
            <div style={{ textAlign: 'center', marginTop: '20px' }}>
              <div style={styles.spinner}></div>
              <p style={{ color: '#FFD700', marginTop: '12px' }}>Girando...</p>
            </div>
          )}

          {result && !playing && (
            <div style={styles.resultBox(result.winAmount > 0)}>
              <p style={styles.resultMsg(result.winAmount > 0)}>{result.message}</p>
              {result.winAmount > 0 && (
                <p style={styles.resultDetails}>Você ganhou: <strong style={{ color: '#00c853' }}>R$ {result.winAmount?.toFixed(2)}</strong></p>
              )}
              {result.spin && <p style={{ fontSize: '36px', marginTop: '8px' }}>{result.spin.join(' ')}</p>}
              {result.diceResult && <p style={{ fontSize: '36px', marginTop: '8px' }}>🎲 {result.diceResult}</p>}
              {result.winningNumber !== undefined && <p style={styles.resultDetails}>Número: {result.winningNumber}</p>}
              <p style={styles.resultDetails}>Novo saldo: R$ {result.newBalance?.toFixed(2)}</p>
            </div>
          )}
        </div>
      )}

      <style>{`@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }`}</style>
    </div>
  );
};

export default Casino;
